/*
 * Filter and Format Articles for AI
 * ==================================
 * Purpose: Filters recent articles and formats them as a numbered list
 *          for AI prompt consumption.
 * 
 * Input: Array of article items from merged RSS feeds
 * Output: Object with articleCount, articlesList (formatted), rawArticles
 * 
 * To customize: Change the UPPERCASE values below
 */

// ⚙️ CONFIGURATION - Edit these to customize behavior
const DAYS_BACK = 7;           // Number of days to look back for articles
const MAX_ARTICLES = 20;       // Maximum number of articles to send to AI
const SNIPPET_LENGTH = 150;    // Maximum characters for article description preview

// ==================== CODE START ====================

// Create a date object for the cutoff point (7 days ago)
const cutoffDate = new Date();
// Subtract DAYS_BACK days from today's date to get the oldest allowed date
cutoffDate.setDate(cutoffDate.getDate() - DAYS_BACK);

// Get all items from the previous node (Merge) and extract just the JSON data
// $input.all() returns all items as array, .map() extracts the .json property from each
const allArticles = $input.all().map(item => item.json);

// Filter, sort, and limit the articles
const processedArticles = allArticles
  // Keep only articles that have a pubDate AND were published after the cutoff
  .filter(article => {
    // Skip articles without a publication date
    if (!article.pubDate) return false;
    // Compare article date with cutoff - keep if newer than cutoff
    return new Date(article.pubDate) >= cutoffDate;
  })
  // Sort by publication date, newest first (descending order)
  // b - a = descending (newest first), a - b would be ascending (oldest first)
  .sort((a, b) => new Date(b.pubDate) - new Date(a.pubDate))
  // Take only the first MAX_ARTICLES items (default: 20)
  .slice(0, MAX_ARTICLES);

// Format articles as a numbered list string for the AI prompt
const formattedList = processedArticles
  .map((article, index) => {
    // Get the article snippet, with fallbacks if contentSnippet doesn't exist
    // Try contentSnippet first, then description, finally use default text
    const snippet = (article.contentSnippet || article.description || 'No description')
      // Truncate to SNIPPET_LENGTH characters to keep the list manageable
      .substring(0, SNIPPET_LENGTH);
    // Format each article as: "1. "Article Title" - Description preview..."
    return `${index + 1}. "${article.title}" - ${snippet}...`;
  })
  // Join all formatted articles with newline characters into one string
  .join('\n');

// ==================== CODE END ======================

// Return the processed data in n8n's required format
// Must return an array of objects, each with a 'json' property
return [{
  json: {
    articleCount: processedArticles.length,  // Number of articles found (for conditional check)
    articlesList: formattedList,              // Formatted string for AI prompt
    rawArticles: processedArticles            // Original article objects (for reference/debugging)
  }
}];

